      "githubUrl": "https://github.com/ascend-ai-coding/awesome-ascend-skills/blob/main/external/cannbot/model/model-infer-migrator/SKILL.md",
      "syncedFrom": "https://gitcode.com/cann/cannbot-skills",
      "referenceCount": 1,
