      "skillFile": "external/gitcode-ascend/triton-operator-code-gen/SKILL.md",
      "githubUrl": "https://github.com/ascend-ai-coding/awesome-ascend-skills/blob/main/external/gitcode-ascend/triton-operator-code-gen/SKILL.md",
